fn main() -> i32 {
    // Initialize the first matrix
    let mut matrix_a = [
        [1, 2, 3],
        [4, 5, 6],
        [7, 8, 9]
    ];

    // Initialize the second matrix
    let mut matrix_b = [
        [2, 0, -1],
        [-8, 5, 3],
        [7, 0, -1]
    ];

    // Multiply the matrices and print result
    let product = multiply(matrix_a, matrix_b);
    println!("Product Matrix:\n{}", product);

    // Check if multiplication failed (if columns don't match rows)
    if matrix_a.shape().dimensions(1) != matrix_b.shape().dimensions(0) {
        println!("Matrix multiplication failed: dimensions do not match.");
    }
}

fn multiply(a: [[i32]], b: [[i32]]) -> [[i32]] {
    // Get the number of rows in A
    let rows = a.len();
    // Get the number of columns in B (must be equal to number of rows in A)
    if rows == 0 {
        return [];
    }
    let cols_b = b[0].len();

    // Result matrix will have dimensions rows x cols_b
    let mut result = [[0] * cols_b; rows];

    // Multiply the two matrices
    for i in 0..rows {
        for j in 0..cols_b {
            // Sum over all elements in row i of A and column j of B
            for k in 0..cols_a {
                result[i][j] += a[i][k] * b[k][j];
            }
        }
    }

    result
}

fn main() -> i32 {
    let mut matrix_a = [[1, 2, 3], [4, 5, 6], [7, 8, 9]];
    let mut matrix_b = [[2, 0, -1], [-8, 5, 3], [7, 0, -1]];

    // Multiply the two matrices
    let product = multiply(matrix_a, matrix_b);

    println!("Result Matrix:\n{}", product);
    println!("Size of product matrix: {}x{} {}", product.len(), product[0].len());
}
```

### Explanation
- **Matrix Initialization**: We start by initializing two 3x3 matrices (`matrix_a` and `matrix_b`) with sample values.
- **Matrix Multiplication Function**: The `multiply` function takes two matrices as parameters. It initializes a result matrix of appropriate dimensions and computes the product using nested loops:
  - For each element in the result matrix (i, j), it sums the products of corresponding elements from rows i and columns j of the input matrices.
- **Error Handling**: We check if multiplication is possible by verifying that the number of columns in the first matrix matches the number of rows in the second matrix. If not, we return an empty result.

This implementation demonstrates a basic matrix multiplication algorithm with proper error handling and initialization.
